// =============== Resolve the body across all webhook shapes ===============
const input = $input.first();
const inputJson = input.json || {};
const inputBinary = input.binary || {};

let body;

// Case A: multipart/form-data - JSON body comes as a binary file under $binary.body
if (inputBinary.body) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'body');
  body = JSON.parse(buffer.toString('utf8'));
}
// Case B: webhook exposes body as a stringified JSON
else if (typeof inputJson.body === 'string') {
  body = JSON.parse(inputJson.body);
}
// Case C: webhook exposes body as a nested object
else if (inputJson.body && typeof inputJson.body === 'object') {
  body = inputJson.body;
}
// Case D: payload is at the top level
else {
  body = inputJson;
}

// =============== Extract fields ===============
const request = body.request || {};
const sessionDetails = request.sessionDetails || '';

const moduleMatch = sessionDetails.match(/Module:\s*(.+?)(?:\n|$)/);
const timeMatch = sessionDetails.match(/Preferred Time:\s*(.+?)(?:\n|$)/);
const module_ = moduleMatch ? moduleMatch[1].trim() : 'N/A';
const preferredTime = timeMatch ? timeMatch[1].trim() : 'N/A';

const ticketId = body.ticketId || '';
const cardId = body.cardId || '';
const responseToken = body.responseToken || '';
const tutorEmail = (body.tutor && body.tutor.email) ? body.tutor.email : '';
const tutorName = (body.tutor && body.tutor.name) ? body.tutor.name : 'Tutor';
const learnerName = (body.learner && body.learner.name) ? body.learner.name : 'N/A';

const acceptUrl = body.callback?.acceptUrl || body.acceptUrl || '';
const refuseUrl = body.callback?.refuseUrl || body.refuseUrl || '';
const emailDeliveryCallback = body.emailDeliveryCallback || {};

// =============== HTML helpers ===============
function escapeHtml(value) {
  return String(value ?? 'N/A')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function formatBytes(value) {
  const size = Number(value || 0);
  if (!Number.isFinite(size) || size <= 0) return '';
  if (size < 1024) return `${size} B`;
  if (size < 1024 * 1024) return `${Math.round(size / 1024)} KB`;
  return `${(size / 1024 / 1024).toFixed(1)} MB`;
}

function infoRow(label, value) {
  return `
    <tr>
      <td style="width:150px;padding:4px 10px 4px 0;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:18px;font-weight:bold;color:#222222;vertical-align:top;">
        ${escapeHtml(label)}
      </td>
      <td style="padding:4px 0;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:18px;color:#444444;vertical-align:top;word-break:break-word;">
        ${escapeHtml(value)}
      </td>
    </tr>
  `;
}

function sectionTitle(title) {
  return `
    <tr>
      <td style="padding:22px 0 10px 0;">
        <div style="font-family:Arial,Helvetica,sans-serif;font-size:12px;line-height:16px;font-weight:bold;color:#777777;text-transform:uppercase;letter-spacing:0.5px;">
          ${escapeHtml(title)}
        </div>
      </td>
    </tr>
  `;
}

function infoBox(rowsHtml, accentColor) {
  return `
    <tr>
      <td style="background:#f8f9fb;border-left:4px solid ${accentColor};border-radius:0 4px 4px 0;padding:14px 18px;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
          ${rowsHtml}
        </table>
      </td>
    </tr>
  `;
}

function normalizeFiles(files) {
  return Array.isArray(files)
    ? files.filter(Boolean).map((file) => ({
        name: file.name || 'attachment',
        mimeType: file.mimeType || 'application/octet-stream',
        size: Number(file.size || 0),
        dataUrl: file.dataUrl || '',
        downloadUrl: file.downloadUrl || '',
        deliveryMode: file.deliveryMode || '',
        deliveryReason: file.deliveryReason || '',
      }))
    : [];
}

function parseSessionsFromText(text) {
  const sessions = [];
  const sessionsMatch = text.match(/Sessions:\n([\s\S]+)/);

  if (sessionsMatch) {
    const lines = sessionsMatch[1].trim().split('\n').filter((line) => line.trim());
    lines.forEach((line, index) => {
      const clean = line.replace(/^\d+\.\s*/, '').trim();
      const parts = clean.split('|').map((part) => part.trim());
      sessions.push({
        label: `Session ${index + 1}`,
        date: parts[0] || 'N/A',
        number: parts[1] ? parts[1].replace('No.', '').trim() : 'N/A',
        subject: parts[2] || 'N/A',
        files: [],
      });
    });
    return sessions;
  }

  const subjectMatch = text.match(/Session Subject:\s*(.+?)(?:\n|$)/);
  if (subjectMatch) {
    sessions.push({
      label: 'Session 1',
      date: 'N/A',
      number: 'N/A',
      subject: subjectMatch[1].trim(),
      files: [],
    });
  }

  return sessions;
}

function fileListHtml(files) {
  if (!files.length) {
    return `
      <tr>
        <td colspan="2" style="padding:8px 0 0 0;font-family:Arial,Helvetica,sans-serif;font-size:12px;line-height:18px;color:#777777;">
          No files attached specifically to this session.
        </td>
      </tr>
    `;
  }

  return `
    <tr>
      <td style="width:150px;padding:8px 10px 4px 0;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:18px;font-weight:bold;color:#222222;vertical-align:top;">
        Attachments
      </td>
      <td style="padding:8px 0 4px 0;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:20px;color:#444444;vertical-align:top;word-break:break-word;">
        ${files.map((file) => {
          const sizeLabel = formatBytes(file.size);
          const fileLabel = `${file.name}${sizeLabel ? ` (${sizeLabel})` : ''}`;
          const linkBadge = file.deliveryMode === 'link'
            ? ' <span style="color:#777777;">secure download link</span>'
            : '';
          if (file.downloadUrl) {
            return `<div style="margin:0 0 6px 0;"><a href="${escapeHtml(file.downloadUrl)}" style="color:#4f46e5;text-decoration:underline;">${escapeHtml(fileLabel)}</a>${linkBadge}</div>`;
          }
          return `<div style="margin:0 0 3px 0;">${escapeHtml(fileLabel)}</div>`;
        }).join('')}
      </td>
    </tr>
  `;
}

// =============== Build sessions array ===============
const parsedSessions = parseSessionsFromText(sessionDetails);
const structuredSessionFiles = Array.isArray(request.sessionFiles) ? request.sessionFiles : [];
const sessions = structuredSessionFiles.length > 0
  ? structuredSessionFiles.map((group, index) => {
      const parsed = parsedSessions[index] || {};
      return {
        label: group.label || parsed.label || `Session ${index + 1}`,
        date: group.date || parsed.date || 'N/A',
        number: group.number || parsed.number || 'N/A',
        subject: group.subject || parsed.subject || 'N/A',
        files: normalizeFiles(group.attachments),
      };
    })
  : parsedSessions;

const generalFiles = normalizeFiles(request.presentationFiles);
const allStructuredFiles = [
  ...generalFiles,
  ...sessions.flatMap((session) => session.files),
];

const sessionCards = sessions.map((session) => `
  <tr>
    <td style="background:#f8f9fb;border-left:4px solid #4a6fa5;border-radius:0 4px 4px 0;padding:14px 18px;">
      <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
        ${infoRow('Date', session.date)}
        ${infoRow('Session No. in Module', session.number)}
        ${infoRow('Subject', session.subject)}
        ${fileListHtml(session.files)}
      </table>
    </td>
  </tr>
  <tr>
    <td style="height:12px;line-height:12px;font-size:12px;">&nbsp;</td>
  </tr>
`).join('');

const generalAttachmentsHtml = generalFiles.length > 0
  ? `
    ${sectionTitle('General Attachments')}
    ${infoBox(
      fileListHtml(generalFiles),
      '#6d5dfc'
    )}
  `
  : '';

// =============== Compose the email ===============
const emailHtml = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Coverage Session Request</title>
</head>
<body style="margin:0;padding:0;background:#f4f4f4;font-family:Arial,Helvetica,sans-serif;">
  <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f4f4f4;margin:0;padding:0;">
    <tr>
      <td align="center" style="padding:24px 12px;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:620px;background:#ffffff;border:1px solid #e0e0e0;border-radius:8px;overflow:hidden;">
          <tr>
            <td style="background:#1a1a2e;padding:26px 30px;">
              <div style="font-family:Arial,Helvetica,sans-serif;color:#aac4f0;font-size:13px;line-height:18px;font-weight:bold;letter-spacing:1px;">
                KENT BUSINESS COLLEGE
              </div>
              <div style="font-family:Arial,Helvetica,sans-serif;color:#ffffff;font-size:20px;line-height:26px;font-weight:bold;margin-top:8px;">
                Coverage Session Request
              </div>
            </td>
          </tr>
          <tr>
            <td style="padding:28px 30px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:22px;color:#555555;padding:0 0 4px 0;">
                    Dear <strong>${escapeHtml(tutorName)}</strong>, you have received a coverage session request. Please review the details below and confirm your availability.
                  </td>
                </tr>

                ${sectionTitle('Request Info')}
                ${infoBox(
                  infoRow('Requested By', learnerName) +
                  infoRow('Module', module_) +
                  infoRow('Session Details', preferredTime),
                  '#1a1a2e'
                )}

                ${generalAttachmentsHtml}

                ${sectionTitle('Sessions That Need To Be Covered')}
                ${sessionCards || `
                  <tr>
                    <td style="background:#f8f9fb;border-left:4px solid #4a6fa5;border-radius:0 4px 4px 0;padding:14px 18px;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:18px;color:#444444;">
                      No sessions were provided.
                    </td>
                  </tr>
                `}

                <tr>
                  <td style="padding-top:20px;">
                    <table role="presentation" cellpadding="0" cellspacing="0" border="0">
                      <tr>
                        <td bgcolor="#2e7d32" style="border-radius:6px;">
                          <a href="${escapeHtml(acceptUrl)}" style="display:inline-block;padding:14px 34px;font-family:Arial,Helvetica,sans-serif;font-size:15px;line-height:18px;font-weight:bold;color:#ffffff;text-decoration:none;border-radius:6px;">
                            &#10003; Accept
                          </a>
                        </td>
                        <td style="width:12px;">&nbsp;</td>
                        <td bgcolor="#c62828" style="border-radius:6px;">
                          <a href="${escapeHtml(refuseUrl)}" style="display:inline-block;padding:14px 34px;font-family:Arial,Helvetica,sans-serif;font-size:15px;line-height:18px;font-weight:bold;color:#ffffff;text-decoration:none;border-radius:6px;">
                            &#10007; Refuse
                          </a>
                        </td>
                      </tr>
                    </table>
                  </td>
                </tr>
              </table>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>
`;

// =============== Build CC list (coach + fixed emails) ===============
const FIXED_CC = [
  'Mohamed.Elmasry@kentbusinesscollege.com',
  'Yousef.Sultan@kentbusinesscollege.com',
  'Ayman.Badewi@kentbusinesscollege.com'
];

const coachEmail = (body.coach && body.coach.email) ? body.coach.email : null;
const ccList = [coachEmail, ...FIXED_CC].filter(Boolean).join(',');

// =============== Attachments ===============
// Two paths:
//   A) Multipart: files come as binary items already (file_0, file_1, ...)
//   B) JSON: files come as base64 dataUrls in body.request.presentationFiles/sessionFiles
const binaryData = {};

// Path A - pass through binary items, skip the "body" item itself
for (const key of Object.keys(inputBinary)) {
  if (key === 'body') continue;
  binaryData[key] = inputBinary[key];
}

// Path B - fallback: build from base64 dataUrls if Path A produced nothing
if (Object.keys(binaryData).length === 0) {
  for (let i = 0; i < allStructuredFiles.length; i++) {
    const file = allStructuredFiles[i];
    if (file && file.dataUrl) {
      binaryData['attachment_' + i] = {
        data: file.dataUrl.split(',')[1],
        mimeType: file.mimeType,
        fileName: file.name,
        fileExtension: (file.name || '').split('.').pop(),
      };
    }
  }
}

const hasAttachments = Object.keys(binaryData).length > 0;

// =============== Output ===============
const result = {
  json: {
    tutorEmail,
    tutorName,
    ticketId,
    cardId,
    responseToken,
    ccList,
    emailSubject: 'Coverage Session Request',
    emailHtml,
    hasAttachments,
    emailDeliveryCallback,
  },
};

if (hasAttachments) {
  result.binary = binaryData;
}

return [result];

const prepared = $('Prepare Email Data').item.json || {};
const gmailResult = $input.first().json || {};

const callback = prepared.emailDeliveryCallback || {};
const messageId = gmailResult.id || gmailResult.messageId || gmailResult.gmailMessageId || '';
const threadId = gmailResult.threadId || gmailResult.gmailThreadId || '';
const rawError = gmailResult.error || gmailResult.message || gmailResult.errorMessage || '';
const errorMessage = typeof rawError === 'string'
  ? rawError
  : (rawError.message || rawError.description || JSON.stringify(rawError));

const failed = Boolean(gmailResult.error) || (!messageId && !threadId);

return [{
  json: {
    ticketId: prepared.ticketId || callback.ticketId || '',
    cardId: prepared.cardId || callback.cardId || '',
    responseToken: prepared.responseToken || callback.responseToken || '',
    tutorEmail: prepared.tutorEmail || '',
    tutorName: prepared.tutorName || '',
    status: failed ? 'failed' : 'sent',
    messageId,
    threadId,
    error: failed ? (errorMessage || 'Gmail delivery failed') : '',
    emailDeliveryCallback: callback,
  },
}];
